class Animal:
    def __init__(self, name: str):
        self.name = name
        self._private = "internal"    # convention
        self.__mangled = "name change"  # name mangling

    def speak(self) -> str:
        return f"{self.name} makes a sound"

    @property
    def info(self):
        return f"Animal: {self.name}"

    @classmethod
    def create(cls, name):
        return cls(name)

    @staticmethod
    def is_alive():
        return True


class Dog(Animal):
    def __init__(self, name, breed):
        super().__init__(name)
        self.breed = breed

    def speak(self):
        return f"{self.name} barks"

# Usage
dog = Dog("Rex", "German Shepherd")
print(dog.speak())
print(dog.info)

